/* ========================================================================
 * Common helpers
 * ====================================================================== */

function getRequestHeaders(config = getConfig()) {
  return {
    "User-Agent": config.userAgent,
    "Content-Type": "application/x-www-form-urlencoded",
    Accept: "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8",
  };
}

function getCasLoginUrl(config = getConfig()) {
  return `${config.casServerUrl}${config.casLoginPath}`;
}

function getCasLogoutUrl(siteUrl: string, config = getConfig()) {
  return `${config.casServerUrl}${config.casLogoutPath}?service=${encodeURIComponent(siteUrl)}&_t=${Date.now()}`;
}

function getCasValidateUrl(config = getConfig()) {
  return `${config.casServerUrl}${config.casValidatePath}`;
}

function getOrigin(request: Handler["request"]): string {
  const rawProto = request.headers["x-forwarded-proto"];
  const proto = Array.isArray(rawProto)
    ? rawProto[0]
    : (rawProto || "http").split(",")[0].trim();
  return `${proto}://${request.host}`;
}

function getOAuthCallbackUrl(request: Handler["request"], config = getConfig()): string {
  return `${getOrigin(request)}${config.oauthCallbackPath}`;
}

function getCasSudoCallbackUrl(request: Handler["request"], config = getConfig()): string {
  return `${getOrigin(request)}${config.sudoCallbackPath}`;
}

function getClientIp(request: Handler["request"]): string {
  const clientIp =
    request.headers["x-forwarded-for"] ||
    request.headers["x-real-ip"] ||
    request.ip ||
    "127.0.0.1";

  return Array.isArray(clientIp)
    ? clientIp[0]
    : clientIp.split(",")[0].trim();
}

function isAjaxRequest(request: Handler["request"]): boolean {
  const accept = request.headers["accept"];
  const xrw = request.headers["x-requested-with"];

  const acceptStr = Array.isArray(accept) ? accept.join(",") : (accept || "");
  const xrwStr = Array.isArray(xrw) ? xrw.join(",") : (xrw || "");

  return (
    acceptStr.includes("application/json") ||
    xrwStr.toLowerCase() === "xmlhttprequest"
  );
}

function ipToNumber(ip: string): number {
  return ip
    .split(".")
    .reduce((acc, octet) => (acc << 8) + parseInt(octet, 10), 0) >>> 0;
}

function isInternalNetwork(ip: string, cidrs?: string[]): boolean {
  const finalCidrs = cidrs || getConfig().intranetCidrs || [];
  const ipNum = ipToNumber(ip);

  for (const cidr of finalCidrs) {
    const [network, prefixLengthRaw] = cidr.split("/");
    const prefixLength = parseInt(prefixLengthRaw, 10);

    if (Number.isNaN(prefixLength) || prefixLength < 0 || prefixLength > 32) {
      continue;
    }

    const networkNum = ipToNumber(network);
    const mask = prefixLength === 0
      ? 0
      : (0xffffffff << (32 - prefixLength)) >>> 0;

    if ((ipNum & mask) === (networkNum & mask)) {
      return true;
    }
  }

  return false;
}

function toErrMsg(e: unknown, fallback = "Request failed"): string {
  if (axios.isAxiosError(e)) {
    const ae = e as AxiosError;
    if (ae.response) return `${fallback} (HTTP ${ae.response.status})`;
    if (ae.request) return `${fallback} (no response)`;
    return `${fallback}: ${ae.message}`;
  }
  if (e instanceof Error) return `${fallback}: ${e.message}`;
  return fallback;
}

function buildCookieString(fromSetCookieHeader?: string[] | string): string {
  if (!fromSetCookieHeader) return "";
  const parsed = setCookie.parse(fromSetCookieHeader as any);
  return parsed.map((c) => `${c.name}=${c.value}`).join("; ");
}

function buildRemoteId(userInfo: AttributeObject): string {
  return `${userInfo.user_id}@cas.dlufl.local`;
}

function buildAuthProfile(userInfo: AttributeObject, config = getConfig()) {
  return {
    _id: buildRemoteId(userInfo),
    email: `${userInfo.id_number}@${config.emailDomain}`,
    uname: [userInfo.id_number].filter(Boolean),
  };
}

function getTokenStoreColl(ctx: Context) {
  return ctx.db.collection("dlufl_token_store");
}

function isLoggedInHandlerUser(h: Handler): boolean {
  return !!(h.user && (h.user as any)._id && Number((h.user as any)._id) !== 0);
}

function generateNonce() {
  return `${Date.now()}_${Math.random().toString(36).slice(2, 12)}`;
}

function getSessionAuthProvider(h: Handler): string {
  return String((h.session as any).authProvider || "");
}

function isCasSession(h: Handler, config = getConfig()): boolean {
  return getSessionAuthProvider(h) === config.providerKey;
}

/* ========================================================================
 * CAS helpers
 * ====================================================================== */

async function getLoginTokens(
  serviceUrl: string,
  config = getConfig()
): Promise<Result<{ lt: string; execution: string; cookie: string }>> {
  try {
    const initResponse: AxiosResponse = await axios.get(
      `${getCasLoginUrl(config)}?service=${encodeURIComponent(serviceUrl)}&renew=true&_=${Date.now()}`,
      {
        headers: getRequestHeaders(config),
        timeout: config.axiosTimeoutMs,
      }
    );

    const initSetCookieHeader = initResponse.headers["set-cookie"];
    if (!initSetCookieHeader) {
      return { success: false, message: "Remote server error: no Set-Cookie." };
    }

    const initCookies = setCookie.parse(initSetCookieHeader);
    const hasSession = initCookies.some((c) => c.name.startsWith("JSESSIONIDCAS"));
    if (!hasSession) {
      return { success: false, message: "Remote server error: no session." };
    }

    const cookieString = buildCookieString(initSetCookieHeader);
    const $init = cheerio.load(initResponse.data);
    const lt = ($init("#lt").val() as string) || "";
    const execution = ($init('input[name="execution"]').val() as string) || "";

    if (!lt || !execution) {
      return { success: false, message: "Failed to get login tokens (lt/execution)." };
    }

    return {
      success: true,
      data: { lt, execution, cookie: cookieString },
    };
  } catch (e) {
    return { success: false, message: toErrMsg(e, "Get login tokens failed") };
  }
}

async function submitLogin(
  cookie: string,
  rsa: string,
  ul: string,
  pl: string,
  lt: string,
  execution: string,
  serviceUrl: string,
  config = getConfig()
): Promise<Result<{ cookie: string }>> {
  try {
    const loginResponse: AxiosResponse = await axios.post(
      `${getCasLoginUrl(config)}?service=${encodeURIComponent(serviceUrl)}`,
      new URLSearchParams({
        rsa,
        ul,
        pl,
        lt,
        execution,
        _eventId: "submit",
      }).toString(),
      {
        headers: { ...getRequestHeaders(config), Cookie: cookie },
        maxRedirects: 0,
        validateStatus: (s) => s >= 200 && s < 400,
        timeout: config.axiosTimeoutMs,
      }
    );

    const loginSetCookieHeader = loginResponse.headers["set-cookie"];
    if (!loginSetCookieHeader) {
      try {
        const $login = cheerio.load(loginResponse.data);
        const loginErrorMsg = $login("#errormsghide").text()?.trim();
        if (loginErrorMsg) return { success: false, message: loginErrorMsg };
      } catch { }
      return { success: false, message: "Login failed: no cookies returned." };
    }

    const parsedLoginCookies = setCookie.parse(loginSetCookieHeader);
    const hasTgc = parsedLoginCookies.some((c) => c.name.startsWith("CASTGC"));
    if (!hasTgc) {
      try {
        const $login = cheerio.load(loginResponse.data);
        const loginErrorMsg = $login("#errormsghide").text()?.trim();
        if (loginErrorMsg) return { success: false, message: loginErrorMsg };
      } catch { }
      return { success: false, message: "Login failed: no CASTGC cookie." };
    }

    const newCookie = parsedLoginCookies
      .filter((c) => c.name !== "Language")
      .map((c) => `${c.name}=${c.value}`)
      .join("; ");

    return { success: true, data: { cookie: newCookie } };
  } catch (e) {
    return { success: false, message: toErrMsg(e, "Submit login failed") };
  }
}

async function getTicket(
  cookie: string,
  serviceUrl: string,
  config = getConfig()
): Promise<Result<{ ticket: string }>> {
  try {
    const resp: AxiosResponse = await axios.get(
      `${getCasLoginUrl(config)}?service=${encodeURIComponent(serviceUrl)}`,
      {
        headers: { ...getRequestHeaders(config), Cookie: cookie },
        maxRedirects: 0,
        validateStatus: (s) => s >= 200 && s < 400,
        timeout: config.axiosTimeoutMs,
      }
    );

    const location = resp.headers["location"];
    if (!location) {
      return { success: false, message: "Authorization failed: no redirect." };
    }

    const match = /[?&]ticket=([^&#]*)/.exec(String(location));
    if (!match?.[1]) {
      return { success: false, message: "Authorization failed: no ticket." };
    }

    return { success: true, data: { ticket: match[1] } };
  } catch (e) {
    return { success: false, message: toErrMsg(e, "Get ticket failed") };
  }
}

async function validateCasTicket(
  ticket: string,
  serviceUrl: string,
  config = getConfig()
): Promise<Result<{ userInfo: AttributeObject }>> {
  try {
    const validateResponse: AxiosResponse = await axios.post(
      getCasValidateUrl(config),
      new URLSearchParams({
        service: serviceUrl,
        ticket,
      }).toString(),
      {
        headers: getRequestHeaders(config),
        timeout: config.axiosTimeoutMs,
      }
    );

    const parser = new xml2js.Parser({ explicitArray: false });
    let parsed: any;
    try {
      parsed = await parser.parseStringPromise(validateResponse.data);
    } catch {
      return { success: false, message: "Failed to parse XML." };
    }

    const authSuccess =
      parsed?.["sso:serviceResponse"]?.["sso:authenticationSuccess"];
    if (!authSuccess) {
      return { success: false, message: "Authentication not successful." };
    }

    const rawAttrs = authSuccess["sso:attributes"]?.["sso:attribute"];
    const attrs = Array.isArray(rawAttrs) ? rawAttrs : rawAttrs ? [rawAttrs] : [];

    const userInfo: AttributeObject = {};
    for (const a of attrs) {
      const name = a?.["$"]?.name;
      const value = a?.["$"]?.value ?? "";
      if (name) userInfo[name] = value;
    }

    const requiredFields = config.requiredCasFields?.length
      ? config.requiredCasFields
      : DEFAULT_REQUIRED_FIELDS;

    for (const k of requiredFields) {
      if (!userInfo[k]) {
        return {
          success: false,
          message: `Missing required user info: ${k}`,
        };
      }
    }

    return { success: true, data: { userInfo } };
  } catch (e) {
    return { success: false, message: toErrMsg(e, "Validate ticket failed") };
  }
}

/* ========================================================================
 * Binding helpers
 * ====================================================================== */

async function ensureBindingByUserInfo(
  ctx: Context,
  userInfo: AttributeObject,
  config = getConfig()
): Promise<void> {
  const rId = buildRemoteId(userInfo);

  const u = await ctx.db.collection("user").findOne({
    $or: [
      { uname: String(userInfo.id_number) },
      { unameLower: String(userInfo.id_number).toLowerCase() },
    ],
  });

  if (!u) {
    throw new ForbiddenError(
      "User does not exist. Maybe it was not imported yet?",
      String(userInfo.id_number),
      String(userInfo.user_id)
    );
  }

  const existingForUser = await ctx.db.collection("oauth").findOne({
    platform: config.providerKey,
    uid: u._id,
  });

  if (existingForUser && existingForUser.id !== rId) {
    throw new ForbiddenError("This user has been bound to another CAS account.");
  }

  const existingUidForId = await ctx.oauth.get(config.providerKey, rId);

  if (existingUidForId && existingUidForId !== u._id) {
    throw new ForbiddenError("This CAS account has been bound to another user.");
  }

  if (existingUidForId !== u._id) {
    await ctx.oauth.set(config.providerKey, rId, u._id);
  }
}

async function getBoundUidByUserInfo(
  ctx: Context,
  userInfo: AttributeObject,
  config = getConfig()
): Promise<any> {
  const rId = buildRemoteId(userInfo);
  return await ctx.oauth.get(config.providerKey, rId);
}

/* ========================================================================
 * OAuth provider registration
 * ====================================================================== */

function registerOAuthProvider(ctx: Context, config = getConfig()) {
  ctx.oauth.provide(config.providerKey, {
    text: config.providerText,
    name: config.providerName,
    icon,
    canRegister: config.canRegister,

    callback: async function callback(this: Handler, { ticket }) {
      const callbackUrl = getOAuthCallbackUrl(this.request, config);
      if (!ticket) throw new ForbiddenError("Missing ticket parameter");

      const validateResult = await validateCasTicket(ticket, callbackUrl, config);
      if (!validateResult.success) {
        throw new ForbiddenError(validateResult.message);
      }

      const { userInfo } = validateResult.data;

      await ensureBindingByUserInfo(ctx, userInfo, config);

      (this.session as any).authProvider = config.providerKey;

      return buildAuthProfile(userInfo, config);
    },

    async get(this: Handler) {
      const callbackUrl = getOAuthCallbackUrl(this.request, config);
      const actualIp = getClientIp(this.request);
      const internal = isInternalNetwork(actualIp, config.intranetCidrs);

      if (!internal) {
        this.response.redirect = `${getCasLoginUrl(config)}?service=${encodeURIComponent(callbackUrl)}`;
        return;
      }

      this.response.body = {
        isInternal: true,
        callbackUrl,
        tokenUrl: `${config.tokenRoutePath}?serviceUrl=${encodeURIComponent(callbackUrl)}`,
        submitUrl: `${config.submitRoutePath}?serviceUrl=${encodeURIComponent(callbackUrl)}`,
        finalCallbackUrl: callbackUrl,
        casLoginUrl: `${getCasLoginUrl(config)}?service=${encodeURIComponent(callbackUrl)}`,
        pageTitle: config.providerText,
      };
      this.response.template = config.internalLoginTemplate;
    },
  });
}

/* ========================================================================
 * Route handlers
 * ====================================================================== */

class LtTokenHandler extends Handler {
  async get() {
    const config = getConfig();
    const callbackUrl = this.request.query.serviceUrl || getOAuthCallbackUrl(this.request, config);
    const actualIp = getClientIp(this.request);

    if (!isInternalNetwork(actualIp, config.intranetCidrs)) {
      this.response.body = {
        success: false,
        message: "Username/password login is only allowed from internal network",
      };
      return;
    }

    const tokenResult = await getLoginTokens(String(callbackUrl), config);
    if (!tokenResult.success) {
      this.response.body = {
        success: false,
        message: tokenResult.message,
      };
      return;
    }

    const { lt, execution, cookie } = tokenResult.data;
    const token = `${Date.now()}_${Math.random().toString(36).slice(2, 11)}`;
    const now = new Date();
    const expiresAt = new Date(now.getTime() + config.tokenTtlMs);

    await getTokenStoreColl(this.ctx).insertOne({
      token,
      cookie,
      lt,
      execution,
      createdAt: now,
      expiresAt,
    } as any);

    this.response.body = { token, lt, execution };
  }
}

class SubmitHandler extends Handler {
  async post() {
    const config = getConfig();
    const callbackUrl = this.request.query.serviceUrl || getOAuthCallbackUrl(this.request, config);
    const actualIp = getClientIp(this.request);

    if (!isInternalNetwork(actualIp, config.intranetCidrs)) {
      this.response.body = {
        success: false,
        message: "Username/password login is only allowed from internal network",
      };
      return;
    }

    const { token, rsa, ul, pl, execution } = this.request.body;

    if (!token || !rsa || !ul || !pl || !execution) {
      this.response.body = {
        success: false,
        message: "Invalid payload",
      };
      return;
    }

    const tokenStore = (await getTokenStoreColl(this.ctx).findOne({ token })) as TokenStore | null;
    if (!tokenStore) {
      this.response.body = {
        success: false,
        message: "Invalid payload or token expired",
      };
      return;
    }

    if (tokenStore.execution !== execution) {
      this.response.body = {
        success: false,
        message: "Invalid payload",
      };
      return;
    }

    const loginResult = await submitLogin(
      tokenStore.cookie,
      rsa,
      String(ul),
      String(pl),
      tokenStore.lt,
      String(execution),
      String(callbackUrl),
      config
    );

    await getTokenStoreColl(this.ctx).deleteOne({ token });

    if (!loginResult.success) {
      this.response.body = {
        success: false,
        message: loginResult.message,
      };
      return;
    }

    const ticketResult = await getTicket(loginResult.data.cookie, String(callbackUrl), config);
    if (!ticketResult.success) {
      this.response.body = {
        success: false,
        message: ticketResult.message,
      };
      return;
    }

    this.response.body = {
      success: true,
      ticket: ticketResult.data.ticket,
    };
  }
}

class CasUniLogoutHandler extends Handler {
  noCheckPermView = true;

  async get() {
    const config = getConfig();
    const actualIp = getClientIp(this.request);
    const internal = isInternalNetwork(actualIp, config.intranetCidrs);

    if (internal) {
      this.response.redirect = "/";
      return;
    }

    const siteUrl = getOrigin(this.request);
    this.response.redirect = getCasLogoutUrl(siteUrl, config);
  }
}

class CasSudoStatusHandler extends Handler {
  noCheckPermView = true;

  async get() {
    const config = getConfig();
    this.response.body = {
      enabled: isLoggedInHandlerUser(this) && isCasSession(this, config),
      provider: getSessionAuthProvider(this),
      url: config.sudoRoutePath,
    };
  }
}

class CasSudoStartHandler extends Handler {
  noCheckPermView = true;

  async get() {
    const config = getConfig();

    if (!isLoggedInHandlerUser(this)) {
      throw new ForbiddenError("Login required.");
    }
    if (!isCasSession(this, config)) {
      throw new CasSudoNotAvailableError();
    }

    (this.session as any).casSudoPending = {
      nonce: generateNonce(),
      createdAt: Date.now(),
      uid: (this.user as any)._id,
    };

    const callbackUrl = getCasSudoCallbackUrl(this.request, config);
    const actualIp = getClientIp(this.request);
    const internal = isInternalNetwork(actualIp, config.intranetCidrs);

    if (!internal) {
      this.response.redirect = `${getCasLoginUrl(config)}?service=${encodeURIComponent(callbackUrl)}`;
      return;
    }

    this.response.body = {
      isInternal: true,
      callbackUrl,
      tokenUrl: `${config.tokenRoutePath}?serviceUrl=${encodeURIComponent(callbackUrl)}`,
      submitUrl: `${config.submitRoutePath}?serviceUrl=${encodeURIComponent(callbackUrl)}`,
      finalCallbackUrl: callbackUrl,
      casLoginUrl: `${getCasLoginUrl(config)}?service=${encodeURIComponent(callbackUrl)}`,
      pageTitle: "Confirm with DLUFL-CAS",
      isSudo: true,
    };
    this.response.template = config.internalLoginTemplate;
  }
}

class CasSudoCallbackHandler extends Handler {
  noCheckPermView = true;

  async get() {
    const config = getConfig();

    if (!isLoggedInHandlerUser(this)) {
      throw new ForbiddenError("Login required.");
    }
    if (!isCasSession(this, config)) {
      throw new CasSudoNotAvailableError();
    }

    const pending = (this.session as any).casSudoPending;
    if (!pending || !pending.createdAt || Date.now() - pending.createdAt > config.sudoPendingTtlMs) {
      delete (this.session as any).casSudoPending;
      throw new CasSudoExpiredError();
    }
    if (String(pending.uid) !== String((this.user as any)._id)) {
      delete (this.session as any).casSudoPending;
      throw new CasSudoMismatchError();
    }

    const ticket = (this.request.query as any)?.ticket;
    if (!ticket) {
      delete (this.session as any).casSudoPending;
      throw new ForbiddenError("Missing ticket parameter");
    }

    const callbackUrl = getCasSudoCallbackUrl(this.request, config);
    const validateResult = await validateCasTicket(String(ticket), callbackUrl, config);
    if (!validateResult.success) {
      delete (this.session as any).casSudoPending;
      throw new ForbiddenError(validateResult.message);
    }

    const userInfo = validateResult.data.userInfo;
    const boundUid = await getBoundUidByUserInfo(this.ctx, userInfo, config);

    delete (this.session as any).casSudoPending;

    if (!boundUid || String(boundUid) !== String((this.user as any)._id)) {
      throw new CasSudoMismatchError();
    }

    (this.session as any).sudo = Date.now();

    const sudoArgs = (this.session as any).sudoArgs || {};
    const method = String(sudoArgs.method || "").toLowerCase();

    if (method && method !== "get") {
      this.response.template = "user_sudo_redirect.html";
      this.response.body = sudoArgs;
      return;
    }

    this.response.redirect = sudoArgs.redirect || "/";
  }
}

/* ========================================================================
 * Guards
 * ====================================================================== */

function sessionIsAdmin(h: any): boolean {
  try {
    return !!h.user && h.user.hasPerm(PERM.PERM_ALL);
  } catch {
    return false;
  }
}

async function targetUserIsAdmin(h: any): Promise<boolean> {
  try {
    const body = (h.request?.body ?? {}) as any;
    const uname: string | undefined = body?.uname || body?.mail || body?.username;
    if (!uname) return false;

    const domainId = h.domainId || "system";
    const udoc =
      (await user.getByEmail(domainId, uname)) ||
      (await user.getByUname(domainId, uname)) ||
      (await user.getByEmail("system", uname)) ||
      (await user.getByUname("system", uname));

    return !!udoc && udoc.hasPerm(PERM.PERM_ALL);
  } catch {
    return false;
  }
}

function getOAuthType(h: any): string {
  return (
    h?.args?.type ||
    (h.request?.params && (h.request.params as any).type) ||
    (h.request?.query && (h.request.query as any).type) ||
    ""
  );
}

function isWebAuthnLogin(h: any): boolean {
  const q = (h.request?.query ?? {}) as any;
  const v = q?.login;
  return v === true || v === "true" || v === 1 || v === "1";
}

function oauthGuard(h: any): void {
  const config = getConfig();
  if (sessionIsAdmin(h)) return;
  const type = getOAuthType(h);
  if (type !== config.providerKey) {
    throw new OAuthProviderNotAllowedError(type || "(empty)");
  }
}

async function passwordLoginGuard(h: any): Promise<void> {
  const config = getConfig();
  if (sessionIsAdmin(h)) return;
  const adminTarget = await targetUserIsAdmin(h);
  if (!adminTarget) {
    throw new PasswordLoginDisabledError(config.providerDisplayName);
  }
}

function webauthnGuard(h: any): void {
  const config = getConfig();
  if (sessionIsAdmin(h)) return;
  if (isWebAuthnLogin(h)) {
    throw new WebAuthnLoginDisabledError(config.providerDisplayName);
  }
}

function registerGuard(h: any): void {
  const config = getConfig();
  if (sessionIsAdmin(h)) return;
  throw new RegistrationDisabledError(config.providerDisplayName);
}

function lostpassGuard(h: any): void {
  const config = getConfig();
  if (sessionIsAdmin(h)) return;
  throw new LostPassDisabledError(config.providerDisplayName);
}

function sudoGuard(h: any): void {
  const config = getConfig();
  if (sessionIsAdmin(h)) return;
  if (!isCasSession(h, config)) {
    throw new SudoNonCasDisabledError(config.providerDisplayName);
  }
  throw new SudoNonCasDisabledError(config.providerDisplayName);
}

function changeMailGuard(h: any): void {
  const config = getConfig();
  if (sessionIsAdmin(h)) return;
  throw new SecurityChangeMailDisabledError(config.providerDisplayName);
}

function homeSecurityOperationGuard(that: any): void {
  const config = getConfig();
  if (sessionIsAdmin(that)) return;

  const operation = String(that.request?.body?.operation || "");

  switch (operation) {
    case "change_password":
      throw new SecurityChangePasswordDisabledError(config.providerDisplayName);

    case "change_mail":
      throw new SecurityChangeMailDisabledError(config.providerDisplayName);

    case "enable_tfa":
    case "disable_tfa":
      throw new SecurityEnableTfaDisabledError(config.providerDisplayName);

    case "register":
    case "enable_authn":
    case "disable_authn":
      throw new SecurityEnableAuthnDisabledError(config.providerDisplayName);

    default:
      return;
  }
}

/* ========================================================================
 * Logout hooks
 * ====================================================================== */

function rememberLogoutProvider(h: Handler) {
  (h.session as any).__preLogoutAuthProvider = (h.session as any).authProvider || "";
}

async function casLogoutAfterHook(h: Handler): Promise<void> {
  const config = getConfig();
  const preLogoutAuthProvider = (h.session as any).__preLogoutAuthProvider || "";
  delete (h.session as any).__preLogoutAuthProvider;

  if (preLogoutAuthProvider !== config.providerKey) return;

  const actualIp = getClientIp(h.request);
  const internal = isInternalNetwork(actualIp, config.intranetCidrs);

  if (internal) {
    if (isAjaxRequest(h.request)) {
      h.response.body = {
        success: true,
        url: "/",
      };
      h.response.redirect = "/";
      return;
    }

    h.response.redirect = "/";
    return;
  }

  const redirectUrl = config.logoutBridgePath;

  if (isAjaxRequest(h.request)) {
    h.response.body = {
      success: true,
      url: redirectUrl,
    };
    h.response.redirect = redirectUrl;
    return;
  }

  h.response.redirect = redirectUrl;
}

/* ========================================================================
 * Session source normalization
 * ====================================================================== */

function markLocalLoginSession(h: Handler) {
  if ((h.session as any).uid && (h.session as any).uid !== 0) {
    (h.session as any).authProvider = "local";
  }
}

