async function setupIndexes(ctx: Context) {
  const coll = getTokenStoreColl(ctx);
  await coll.createIndex({ expiresAt: 1 }, { expireAfterSeconds: 0 });
  await coll.createIndex({ token: 1 }, { unique: true });
}

